import{abrirMenu,armarTestimonios}from './ui.min.js';import{getData}from './api.min.js';import{validarFormulario}from './validaciones.min.js';document.addEventListener('DOMContentLoaded',async ()=>{console.log('dom listo');document.querySelector('.menu').addEventListener('click',abrirMenu);document.querySelector('.nav-link').addEventListener('click',abrirMenu);const dataTestimonios=await getData();armarTestimonios(dataTestimonios,"#testimonios");document.querySelector('#form-contacto').addEventListener('input',()=>{validarFormulario('#form-contacto','#btn-submit')});document.querySelector('#form-contacto').addEventListener('submit',(event)=>{event.preventDefault();console.log(validarFormulario('#form-contacto','#btn-submit'));if(validarFormulario('#form-contacto','#btn-submit')){alert('Formulario enviado correctamente');document.querySelector('#form-contacto').reset()}else{alert('Todos los campos son obligatorios')}})});